import React from "react";
import Filho from './Filho';

const Pai = props =>
    <div>
        <h1>{props.nome} {props.sobrenome}</h1>
        <h2>Filhos</h2>
        <ul>
            {props.children} {/* Aqui serão renderizados os filhos */}
            {React.cloneElement(props.children, { ...props })} {/* estamos adicionando propriedades os elementos clonado*/}
        </ul>
    </div>
export default Pai
